import { execution } from '@dynatrace-sdk/automation-utils';

export default async function ({ executionId }) {
  const { input } = await fetch(`/platform/automation/v1/executions/${executionId}`).then((res) => res.json());

  try {
    const riskPorts = [22, 3389, 1433, 5432, 3306, 5984, 6379, 7001, 8080, 9200];
    const port = parseInt(input.sensitivePort);

    if (!riskPorts.includes(port)) {
      console.warn(`Port ${port} is not in standard high-risk list, but remediation may still be valid`);
    }

    return {
      groupId: input.groupIdorName,
      targetPort: port,
      action: 'close_public_access',
      region: input.awsRegion,
      risk: riskPorts.includes(port) ? 'HIGH' : 'MEDIUM',
      status: 'ready_for_remediation',
      recommendation: `Restrict port ${port} access to specific IP ranges or security groups instead of 0.0.0.0/0`
    };
  } catch (error) {
    console.error('Error validating remediation:', error);
    throw new Error(`Failed to validate remediation: ${error}`);
  }
}
